from langgraph.graph import StateGraph
from collections import defaultdict

def detect_cycles(graph, config, max_iterations=50):
    visited = defaultdict(int)
    state_hash = None

    for i in range(max_iterations):
        result = graph.invoke(None, config)
        current_hash = hash(str(result))
        visited[list(result.keys())[0]] += 1

        if current_hash == state_hash and i > 10:
            return {'error': 'CYCLE_DETECTED', 'iterations': i}
        state_hash = current_hash
    return {'status': 'healthy'}

import langgraph

def scan_state_corruption(final_state, expected_schema):
    errors = []
    for key, expected_type in expected_schema.items():
        value = final_state.get(key)
        if value is None:
            errors.append(f'{key}: NULL_VALUE')
        elif not isinstance(value, expected_type):
            errors.append(f'{key}: TYPE_MISMATCH expected={expected_type} got={type(value)}')
    return {'corrupted': len(errors) > 0, 'errors': errors}

