from vex_sdk import verify
from langgraph.graph import StateGraph

# Method 1: Wrap invoke
@verify(agent='langgraph-agent')
def run_agent(input_data):
    app.invoke(input_data, config)

# Method 2: Vex as graph node
def vex_observer(state):
    verify_result = verify.check({
        'state_snapshot': state,
        'node': 'current_node',
        'metrics': {'iteration': state.get('iteration', 0)}
    })
    if verify_result.errors:
        return {'error': 'VEX_BLOCKED'}
    return state

workflow.add_node('vex_check', vex_observer)
app = workflow.compile()
